output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(SUM(?games) AS ?totalGames) WHERE {
  ?series wdt:P361 wd:Q1363275 .
  ?series wdt:P571 ?date .
  FILTER(year(?date) >= 1978 && year(?date) <= 2009)
  .
  {
    ?series wdt:P3866 wd:Q334634 .
    ?series wdt:P3867 wd:Q650840 .
  } UNION {
    ?series wdt:P3866 wd:Q650840 .
    ?series wdt:P3867 wd:Q334634 .
  }
  ?series wdt:P2538 ?games .
}

